def test_bb_40_audit(client, admin_headers):
    """BB-40: Retrieve audit record."""
    assert test_state["vc"] is not None
    payload = {
        "credential": test_state["vc"],
        "presenterId": "agent-123",
        "requestContext": {
            "action": "damage_assessment:read",
            "resource": "/claims/CLM-2026-0001",
            "claimAmount": 4200,
            "claimType": "rear_end"
        }
    }
    r = client.post(f"{ENGINE_URL}/evaluate", json=payload)
    audit_id = r.json()["auditRecordId"]
    
    # Wait a moment for background signing
    time.sleep(2)
    
    r_audit = client.get(f"{ENGINE_URL}/audit/records/{audit_id}", headers=admin_headers)
    assert r_audit.status_code == 200
    assert r_audit.json()["decision"] == "allow"
